INSERT INTO questions (exam_id, subject_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES
('e33338c9-740c-48c4-914b-2cca3e9c1668', '3f275622-18e3-40ce-a134-ec660b48190c', 2023, 'Paper-II', 'Which of the following rules related to ''scale'' is True or False? Rule 1: Choose a scale large enough... Rule 2: Choose as small a scale...', 'Rule 1 is True and Rule 2 is False', 'Rule 1 is False and Rule 2 is True', 'Both Rule 1 & Rule 2 are True', 'Both Rule 1 & Rule 2 are False', 3, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', '3f275622-18e3-40ce-a134-ec660b48190c', 2023, 'Paper-II', 'Which of the following statement(s) is/are incorrect about characteristics of contour lines? (i) Irregular contours represent uneven ground. (ii) A contour line must close onto itself, not necessarily within the limits of a map. (iii) Equally spaced concentric contour lines represent an overhanging cliff.', 'Only (i)', 'Only (ii)', 'Only (iii)', '(i) and (ii) only', 3, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', '3f275622-18e3-40ce-a134-ec660b48190c', 2023, 'Paper-II', 'Arrange the following length measurements in the increasing order. A. One Mile length B. One Gunter chain length C. One Furlong length D. One Revenue chain length', 'A, B, C, D', 'D, B, C, A', 'D, C, B, A', 'C, A, B, D', 2, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', '3f275622-18e3-40ce-a134-ec660b48190c', 2023, 'Paper-II', 'Which of the following is the correct chronological order (from the earliest to the latest) of temporary adjustments for Levelling Instrument? P. Elimination of Parallax Q. Setting up the level R. Levelling up', 'Q, R, P', 'R, Q, P', 'P, Q, R', 'Q, P, R', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'a3efd61d-542a-4076-8ffe-631b227f0239', 2023, 'Paper-II', 'What is the maximum limit of cold water absorption for Common Burnt Clay Bricks of Class Designation 30, according to IS 1077: 1992?', '20%', '10%', '15%', '25%', 3, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'a3efd61d-542a-4076-8ffe-631b227f0239', 2023, 'Paper-II', 'Which of the following statement is/are correct or incorrect related to determination of compressive strength of Ordinary Portland cement according to IS: 4031 (Part 6) - 1988? Statements: 1. The side of the cubical testing mould is 50.6mm 2. The curing temperature in water should be 27±2°C', 'Both statements are correct', 'Statement 1 is incorrect and statement 2 is correct', 'Both statements are incorrect', 'Statement 1 is correct and statement 2 is incorrect', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'a3efd61d-542a-4076-8ffe-631b227f0239', 2023, 'Paper-II', 'Arrange the given manufacturing steps of Encaustic tiles in the chronological order (from the earliest to the latest). A. The maker''s name is stamped on the back. B. The coarser clay body is put on the back of the face and also a thin coat to form the back. C. The face is moulded to the desired pattern. D. A few holes are kept for joining with cement during laying.', 'D, B, C, A', 'A, B, C, D', 'B, C, D, A', 'C, B, A, D', 4, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'a3efd61d-542a-4076-8ffe-631b227f0239', 2023, 'Paper-II', 'Which of the following statements is/are correct with respect to Good Timber? Statements: (i) The well- seasoned timber with high weight is considered to be sound and strong. (ii) A good timber should have high water permeability. (iii) A dull heavy sound, when struck, indicates decayed timber.', '(i) and (ii) only', 'Only (ii)', 'Only (iii)', '(i) and (iii) only', 4, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'a3efd61d-542a-4076-8ffe-631b227f0239', 2023, 'Paper-II', 'As per IS 1141: 1993 and for the purpose of seasoning, ''Highly Refractory'' timbers are classified as depending upon their behaviour with respect to cracking and splitting, and drying rate.', 'Class D', 'Class C', 'Class A', 'Class B', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'a3efd61d-542a-4076-8ffe-631b227f0239', 2023, 'Paper-II', 'Which of the following types of plaster is used in X- Ray rooms as the final coat?', 'Acoustic Plaster', 'Asbestos-Marble Plaster', 'Barium Plaster', 'Granite Silicon Plaster', 3, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'a3efd61d-542a-4076-8ffe-631b227f0239', 2023, 'Paper-II', 'According to National Building Code (NBC) 2016 Part 6 Section 2, for general guidance, what will be the correct depth of exploration (D) at the start of the work if the type of foundation is Raft?', '2 m below ground level or equal to the height of the fill, whichever is greater', 'Equal to the bottom width of the cut', 'One and half times the Length (L) of footing', 'One and a half times the width (B)', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'a3efd61d-542a-4076-8ffe-631b227f0239', 2023, 'Paper-II', 'Arrange the following parts of the well foundation in sequential order from bottom to top. A. Steining B. Well Cap C. Well Curb D. Cutting Edge', 'A, D, C, B', 'D, C, B, A', 'A, B, C, D', 'D, C, A, B', 4, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'aee3c24f-8b41-461f-8e64-e9544a04c1b6', 2023, 'Paper-II', 'How much area should be increased for color washing of corrugated steel sheet?', '25%', '14%', '50%', '35%', 2, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'aee3c24f-8b41-461f-8e64-e9544a04c1b6', 2023, 'Paper-II', 'Estimate the cost of brickwork required in a wall 4m long, 3m high, and 150mm thick and the rate of brickwork is 400 per cum. No Deduction shall be done.', '720', '840', '960', '480', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'aee3c24f-8b41-461f-8e64-e9544a04c1b6', 2023, 'Paper-II', 'According to IS: 1200 (Part V), identify whether the given statements related to estimation of formwork in RCC are correct or incorrect. Statements: 1. No deduction shall be made for ventilators having an opening of 1.5m² area. 2. Circular cutting and rounded edges shall be measured in running metres.', 'Statement 1 is correct and Statement 2 is incorrect', 'Statement 1 is incorrect and Statement 2 is correct', 'Both Statements 1 and 2 are correct', 'Both Statements 1 and 2 are incorrect', 3, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'aee3c24f-8b41-461f-8e64-e9544a04c1b6', 2023, 'Paper-II', 'Which of the following statement(s) is/are correct about the lead & lift in Estimation? Statements: 1. The unit of lead is 50m for a distance up to 500m 2. Lift shall be measured from ground level. 3. The unit of lead is 500m for a distance exceeding 500m up to 5km', '1 and 2 Only', '2 and 3 Only', 'All Statements 1, 2 and 3', '1 and 3 Only', 4, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'aee3c24f-8b41-461f-8e64-e9544a04c1b6', 2023, 'Paper-II', 'Match the items under List 1 (Description of Item) with those under List 2 (Unit of Measurement) in Estimating and Costing and choose the correct option. P. Earthwork Q. Clean of Shrubs, Brushwood and small tree R. Expansion Joint work in Concrete S. Reinforcement', 'P-4,Q-1,R-2,S-3', 'P-2,Q-4,R-1,S-3', 'P-3,Q-1,R-4,S-2', 'P-4,Q-3,R-1,S-2', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'a8556419-0986-4502-80b2-78b7defb8990', 2023, 'Paper-II', 'What will be the specific weight of one litre of liquid which has a weight of 9.81 N?', '1000 N/m³', '981 N/m³', '0.00981 N/m³', '9810 N/m³', 4, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'a8556419-0986-4502-80b2-78b7defb8990', 2023, 'Paper-II', 'Identify the correct ratio of the loss of head at the entrance of a pipe (h_i) to the Loss of head at the exit of pipe (h_o)', 'Ratio = 0.25', 'Ratio = 0.5', 'Ratio = 2', 'Ratio = 4', 2, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'a8556419-0986-4502-80b2-78b7defb8990', 2023, 'Paper-II', 'Calculate the corresponding height of fluid (oil) of specific gravity of 0.9, if the pressure intensity at a point in a fluid is given as 3.6 N/cm². Take g = 10 m/s².', '0.9 m of oil', '3.6 m of oil', '4 m of oil', '10 m of oil', 3, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'a8556419-0986-4502-80b2-78b7defb8990', 2023, 'Paper-II', 'Identify whether the given statements related to pressure measurement are correct or incorrect. Statements: 1. Absolute Pressure is equal to sum of atmospheric pressure and gauge pressure. 2. The atmospheric pressure at sea level and at 15°C is equal to 1.033 kN/m²', 'Statement 1 is correct and Statement 2 is incorrect', 'Statement 1 is incorrect and Statement 2 is correct', 'Both Statements 1 and 2 are correct', 'Both Statements 1 and 2 are incorrect', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'a8556419-0986-4502-80b2-78b7defb8990', 2023, 'Paper-II', 'Which of the following is the mismatched pair of type of flow for the given value of Reynolds Number?', 'Laminar Flow in pipe = 1000', 'Laminar Flow in open channel = 2000', 'Turbulent Flow in open channel = 3500', 'Turbulent Flow in pipe = 5000', 2, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'a8556419-0986-4502-80b2-78b7defb8990', 2023, 'Paper-II', 'Which of the following is the correct chronological order/sequence of the arrangement of parts for the lifting of water by reciprocating pump from bottom to top? A. Suction Valve B. Delivery Valve C. Suction Pipe D. Delivery Pipe', 'C, A, B, D', 'D, C, B, A', 'B, D, A, C', 'C, D, B, A', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', '637bf719-8dde-4035-946c-4242372328e2', 2023, 'Paper-II', 'Identify the correct IRC Code which is referred for the guidelines for the Road Signs?', 'IRC:56', 'IRC:37', 'IRC:67', 'IRC:35', 3, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', '637bf719-8dde-4035-946c-4242372328e2', 2023, 'Paper-II', 'In a district with heavy rainfall, WBM (Water Bound Macadam) of a major district road of 6.6m width, is planned to be constructed. What should be the height of the crown with respect to the edge? Take Camber = 1 in 33', '0.19 m', '0.035 m', '0.058 m', '0.1 m', 4, NULL, 'medium')
